-- logsumexp.cpp ------------------------------------------------------
#include <Rcpp.h>
using namespace Rcpp;

// [[Rcpp::export]]
NumericVector logsumexp_Rcpp(NumericMatrix x, NumericVector a)
{
// Efficiently computes log-sum-exp(x+a)
// x = matrix (n x d)
// a = vector (d)

 double n = x.nrow();
 double d = x.ncol();
 NumericVector lse(n);
 NumericVector xa(d);
 double m = 0.0;
 // 
 for (int i = 0; i < n; i++)
 {
   xa = x.row(i) + a;
   m = max(xa);
   lse[i] = m + log(sum(exp(xa-m)));
 }
 return lse;
}

